<?php include 'includes/config.php'; require_role('seller'); $u=current_user(); if(isset($_GET['delete'])){$id=(int)$_GET['delete'];$pdo->prepare('DELETE FROM products WHERE id=? AND seller_id=?')->execute([$id,$u['id']]); header('Location: manage-products.php');exit;} ?>
<!DOCTYPE html><html><head><title>Manage Products</title><link rel="stylesheet" href="css/styles.css"><script src="js/app.js"></script></head><body><?php include 'includes/header.php'; ?><section class="section"><h1>My Products</h1><div class="grid">
<?php $stmt=$pdo->prepare("SELECT p.*, (SELECT image_path FROM product_images WHERE product_id=p.id LIMIT 1) img FROM products p WHERE seller_id=? ORDER BY created_at DESC");$stmt->execute([$u['id']]);foreach($stmt as $p): ?><div class="card"><img src="<?= clean($p['img'] ?: 'assets/background.png') ?>"><h3><?= clean($p['product_name']) ?></h3><p><?= clean($p['category']) ?></p><p class="price">R<?= number_format($p['price'],2) ?></p><a onclick="return confirmDelete()" href="manage-products.php?delete=<?= $p['id'] ?>">Delete</a></div><?php endforeach; ?>
</div></section></body></html>
